void CompareElevationMapFilterComponent::elevationMapCallback(
  const grid_map_msgs::msg::GridMap::ConstSharedPtr elevation_map)
{
  grid_map::GridMapRosConverter::fromMessage(*elevation_map, elevation_map_);
  elevation_map_data_ = elevation_map_.get(layer_name_);

  const float min_value = elevation_map_.get(layer_name_).minCoeffOfFinites();
  const float max_value = elevation_map_.get(layer_name_).maxCoeffOfFinites();
  grid_map::GridMapCvConverter::toImage<uint16_t, 1>(
    elevation_map_, layer_name_, CV_16UC1, min_value, max_value, elevation_image_);
  subscribe();
}

void autoware::pointcloud_preprocessor::Filter::subscribe(const std::string & filter_name)
{
  // TODO(sykwer): Change the corresponding node to subscribe to `faster_input_indices_callback`
  // each time a child class supports the faster version.
  // When all the child classes support the faster version, this workaround is deleted.
  std::set<std::string> supported_nodes = {
    "CropBoxFilter", "RingOutlierFilter", "VoxelGridDownsampleFilter", "ScanGroundFilter",
    "PointCloudDensifier"};
  auto callback = supported_nodes.find(filter_name) != supported_nodes.end()
                    ? &Filter::faster_input_indices_callback
                    : &Filter::input_indices_callback;

  if (use_indices_) {
    // Subscribe to the input using a filter
    sub_input_filter_.subscribe(
      this, "input", rclcpp::SensorDataQoS().keep_last(max_queue_size_).get_rmw_qos_profile());
    sub_indices_filter_.subscribe(
      this, "indices", rclcpp::SensorDataQoS().keep_last(max_queue_size_).get_rmw_qos_profile());

    if (approximate_sync_) {
      sync_input_indices_a_ = std::make_shared<ApproximateTimeSyncPolicy>(max_queue_size_);
      sync_input_indices_a_->connectInput(sub_input_filter_, sub_indices_filter_);
      sync_input_indices_a_->registerCallback(
        std::bind(callback, this, std::placeholders::_1, std::placeholders::_2));
    } else {
      sync_input_indices_e_ = std::make_shared<ExactTimeSyncPolicy>(max_queue_size_);
      sync_input_indices_e_->connectInput(sub_input_filter_, sub_indices_filter_);
      sync_input_indices_e_->registerCallback(
        std::bind(callback, this, std::placeholders::_1, std::placeholders::_2));
    }
  } else {
    // Subscribe in an old fashion to input only (no filters)
    // CAN'T use auto-type here.
    std::function<void(const PointCloud2ConstPtr msg)> cb =
      std::bind(callback, this, std::placeholders::_1, PointIndicesConstPtr());
    sub_input_ = create_subscription<PointCloud2>(
      "input", rclcpp::SensorDataQoS().keep_last(max_queue_size_), cb);
  }
}

void autoware::pointcloud_preprocessor::Filter::faster_input_indices_callback(
  const PointCloud2ConstPtr cloud, const PointIndicesConstPtr indices)
{
  if (
    !utils::is_data_layout_compatible_with_point_xyzircaedt(*cloud) &&
    !utils::is_data_layout_compatible_with_point_xyzirc(*cloud)) {
    RCLCPP_ERROR(
      get_logger(),
      "The pointcloud layout is not compatible with PointXYZIRCAEDT or PointXYZIRC. Aborting");

    if (utils::is_data_layout_compatible_with_point_xyziradrt(*cloud)) {
      RCLCPP_ERROR(
        get_logger(),
        "The pointcloud layout is compatible with PointXYZIRADRT. You may be using legacy "
        "code/data");
    }

    if (utils::is_data_layout_compatible_with_point_xyzi(*cloud)) {
      RCLCPP_ERROR(
        get_logger(),
        "The pointcloud layout is compatible with PointXYZI. You may be using legacy "
        "code/data");
    }

    return;
  }

  if (!is_valid(cloud, this->get_logger(), *this->get_clock())) {
    RCLCPP_ERROR(this->get_logger(), "[input_indices_callback] Invalid input!");
    return;
  }

  if (indices) {
    if (!is_valid_indices(indices, cloud->width * cloud->height, this->get_logger())) {
      RCLCPP_ERROR(this->get_logger(), "[input_indices_callback] Invalid indices!");
      return;
    }

    RCLCPP_DEBUG(
      this->get_logger(),
      "[input_indices_callback]\n"
      "   - PointCloud with %d data points (%s), stamp %f, and frame %s on input topic received.\n"
      "   - PointIndices with %zu values, stamp %f, and frame %s on indices topic received.",
      cloud->width * cloud->height, pcl::getFieldsList(*cloud).c_str(),
      rclcpp::Time(cloud->header.stamp).seconds(), cloud->header.frame_id.c_str(),
      indices->indices.size(), rclcpp::Time(indices->header.stamp).seconds(),
      indices->header.frame_id.c_str());
  } else {
    RCLCPP_DEBUG(
      this->get_logger(),
      "[input_indices_callback] PointCloud with %d data points and frame %s on input topic "
      "received.",
      cloud->width * cloud->height, cloud->header.frame_id.c_str());
  }

  tf_input_orig_frame_ = cloud->header.frame_id;

  // For performance reason, defer the transform computation.
  // Do not use pcl_ros::transformPointCloud(). It's too slow due to the unnecessary copy.
  TransformInfo transform_info;
  if (!calculate_transform_matrix(tf_input_frame_, *cloud, transform_info)) return;

  // Need setInputCloud() here because we have to extract x/y/z
  IndicesPtr vindices;
  if (indices) {
    vindices.reset(new std::vector<int>(indices->indices));
  }

  auto output = std::make_unique<PointCloud2>();

  // TODO(sykwer): Change to `filter()` call after when the filter nodes conform to new API.
  faster_filter(cloud, vindices, *output, transform_info);

  if (!convert_output_costly(output)) return;

  output->header.stamp = cloud->header.stamp;
  pub_output_->publish(std::move(output));
  published_time_publisher_->publish_if_subscribed(pub_output_, cloud->header.stamp);
}

static bool is_valid(
  const PointCloud2ConstPtr & cloud, const rclcpp::Logger & logger, rclcpp::Clock & clock)
{
  static constexpr rcutils_duration_value_t throttle_duration_ms = 5000;

  if (!cloud) {
    RCLCPP_WARN_THROTTLE(
      logger, clock, throttle_duration_ms, "Invalid PointCloud: Null pointer received.");
    return false;
  }

  // Check: Point Step
  if (cloud->point_step == 0) {
    RCLCPP_WARN_THROTTLE(
      logger, clock, throttle_duration_ms,
      "Invalid PointCloud: point_step is 0. "
      "Frame: '%s', Stamp: %d.%09u",
      cloud->header.frame_id.c_str(), cloud->header.stamp.sec, cloud->header.stamp.nanosec);
    return false;
  }

  // Check: Only accept organized (dense) point clouds
  if (!cloud->is_dense) {
    RCLCPP_WARN_THROTTLE(
      logger, clock, throttle_duration_ms,
      "Invalid PointCloud: is_dense is false. "
      "The point cloud should be organized (dense) and contain only valid points. "
      "This will be an ERROR starting in 2026 July"
      "Frame: '%s', Stamp: %d.%09u",
      cloud->header.frame_id.c_str(), cloud->header.stamp.sec, cloud->header.stamp.nanosec);
    // TODO(mfc): return false; After 2026 July
  }

  // Check: Point field layout compatibility
  if (!utils::is_data_layout_compatible_with_point_xyz(*cloud)) {
    RCLCPP_WARN_THROTTLE(
      logger, clock, throttle_duration_ms,
      "The pointcloud layout is not compatible with PointXYZ. Aborting. "
      "Make sure Point fields start with x, y, z as FLOAT32.");
    return false;
  }

  // Check: Row step consistency
  std::uint64_t expected_row_step =
    static_cast<std::uint64_t>(cloud->width) * static_cast<std::uint64_t>(cloud->point_step);

  if (expected_row_step != static_cast<std::uint64_t>(cloud->row_step)) {
    RCLCPP_WARN_THROTTLE(
      logger, clock, throttle_duration_ms,
      "Invalid PointCloud: row_step mismatch. "
      "Expected: %zu (width %u * point_step %u), Got: %u. "
      "Frame: '%s', Stamp: %d.%09u"
      " Please fill in the `cloud->row_step` field accordingly."
      " This will be an ERROR starting in 2026 July",
      expected_row_step, cloud->width, cloud->point_step, cloud->row_step,
      cloud->header.frame_id.c_str(), cloud->header.stamp.sec, cloud->header.stamp.nanosec);
    // TODO(mfc): return false; After 2026 July
  }

  // Check: Data buffer size consistency
  std::uint64_t expected_data_size =
    static_cast<std::uint64_t>(cloud->height) * expected_row_step;

  if (expected_data_size != cloud->data.size()) {
    RCLCPP_WARN_THROTTLE(
      logger, clock, throttle_duration_ms,
      "Invalid PointCloud: data size mismatch. "
      "Expected: %zu (height %u * row_step %u), Got: %zu. "
      "Frame: '%s', Stamp: %d.%09u",
      expected_data_size, cloud->height, cloud->row_step, cloud->data.size(),
      cloud->header.frame_id.c_str(), cloud->header.stamp.sec, cloud->header.stamp.nanosec);
    return false;
  }

  return true;
}

bool is_data_layout_compatible_with_point_xyz(
  const std::vector<sensor_msgs::msg::PointField> & fields)
{
  if (fields.size() < 3) {
    return false;
  }

  // Expected PointXYZ layout:
  // struct { float x; float y; float z; }
  constexpr size_t offset_x = 0;
  constexpr size_t offset_y = sizeof(float);
  constexpr size_t offset_z = sizeof(float) * 2;

  bool same_layout = true;

  const auto & field_x = fields[0];
  same_layout &= field_x.name == "x";
  same_layout &= field_x.offset == offset_x;
  same_layout &= field_x.datatype == sensor_msgs::msg::PointField::FLOAT32;
  same_layout &= field_x.count == 1;

  const auto & field_y = fields[1];
  same_layout &= field_y.name == "y";
  same_layout &= field_y.offset == offset_y;
  same_layout &= field_y.datatype == sensor_msgs::msg::PointField::FLOAT32;
  same_layout &= field_y.count == 1;

  const auto & field_z = fields[2];
  same_layout &= field_z.name == "z";
  same_layout &= field_z.offset == offset_z;
  same_layout &= field_z.datatype == sensor_msgs::msg::PointField::FLOAT32;
  same_layout &= field_z.count == 1;

  return same_layout;
}

bool autoware::pointcloud_preprocessor::Filter::calculate_transform_matrix(
  const std::string & target_frame, const sensor_msgs::msg::PointCloud2 & from,
  TransformInfo & transform_info /*output*/)
{
  transform_info.need_transform = false;

  if (target_frame.empty() || from.header.frame_id == target_frame) return true;

  RCLCPP_DEBUG(
    this->get_logger(), "[get_transform_matrix] Transforming input dataset from %s to %s.",
    from.header.frame_id.c_str(), target_frame.c_str());

  auto eigen_transform_opt = managed_tf_buffer_->getTransform<Eigen::Matrix4f>(
    target_frame, from.header.frame_id, from.header.stamp, rclcpp::Duration::from_seconds(1.0),
    this->get_logger());
  if (!eigen_transform_opt) {
    return false;
  }

  transform_info.eigen_transform = *eigen_transform_opt;
  transform_info.need_transform = true;
  return true;
}

